import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

const manual_Trigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const full_execution_test = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: { name: 'full execution test', parameters: { assignments: { assignments: [{ id: 'status-assignment', name: 'status', value: 'ready', type: 'string' }] }, options: {} } }
});

const full_execution_test_terminal = node({
  type: 'n8n-nodes-base.noOp',
  version: 1,
  config: { name: 'full execution test terminal' }
});

const wf = workflow('RSCIgFBs66ahLJFw', 'Full Execution Workflow');

export default wf
  .add(manual_Trigger)
  .to(full_execution_test)
  .to(full_execution_test_terminal)
